INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_01$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The room is slightly wrong. Not broken ‚Äì shifted. As if it was assembled from a description, not a blueprint.$Q$, $Q$Der Raum ist leicht falsch. Nicht kaputt ‚Äì verschoben. Als w√§re er aus einer Beschreibung zusammengesetzt, nicht aus einem Bauplan.$Q$, NULL, NULL, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_02$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Something in the architecture anticipates the party. The door was open before they reached it.$Q$, $Q$Etwas in der Architektur nimmt die Gruppe vorweg. Die T√ºr war offen, bevor sie sie erreichten.$Q$, NULL, NULL, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_03$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The corridor is familiar. {agent} has never been here. Both of these are true.$Q$, $Q$Der Korridor ist vertraut. {agent} war nie hier. Beides stimmt.$Q$, NULL, NULL, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_04$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$D√©j√Ý vu. The room adjusts as the party enters, settling into a configuration that almost matches a memory.$Q$, $Q$D√©j√Ý vu. Der Raum justiert sich, als die Gruppe eintritt, und l√§sst sich in eine Konfiguration fallen, die fast einer Erinnerung entspricht.$Q$, NULL, NULL, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_05$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q${agent} enters the room. The room recognizes {agent}. This is not a metaphor.$Q$, $Q${agent} betritt den Raum. Der Raum erkennt {agent}. Das ist keine Metapher.$Q$, NULL, NULL, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_06$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The dungeon's consciousness is perceptible here. Not hostile. Not welcoming. Attentive.$Q$, $Q$Das Bewusstsein des Dungeons ist hier wahrnehmbar. Nicht feindlich. Nicht einladend. Aufmerksam.$Q$, NULL, NULL, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_07$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The room turns ‚Äì left, or the party turned, or the concept of turning shifted. Certainty is expensive here.$Q$, $Q$Der Raum biegt ab ‚Äì links, oder die Gruppe bog ab, oder der Begriff des Abbiegens verschob sich. Gewissheit ist hier teuer.$Q$, NULL, NULL, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_08$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Three agents. Three perceptions. None of them see the same room. All of them see the truth.$Q$, $Q$Drei Agenten. Drei Wahrnehmungen. Keiner sieht denselben Raum. Alle sehen die Wahrheit.$Q$, NULL, NULL, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_09$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$Something surfaces. Not from the shadows ‚Äì from the periphery of recognition.$Q$, $Q$Etwas taucht auf. Nicht aus den Schatten ‚Äì aus der Peripherie der Wiedererkennung.$Q$, NULL, NULL, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_10$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The enemy is familiar. The enemy has always been familiar. The party fights a recognition they cannot place.$Q$, $Q$Der Feind ist vertraut. Der Feind war immer vertraut. Die Gruppe bek√§mpft eine Wiedererkennung, die sie nicht einordnen kann.$Q$, NULL, NULL, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_11$Q$, $Q$The Awakening$Q$, $Q$combat_victory$Q$, $JB${}$JB$::jsonb, $Q$The memory disperses. Not destroyed ‚Äì returned to the substrate. The dungeon absorbs what the party released.$Q$, $Q$Die Erinnerung zerstreut sich. Nicht zerst√∂rt ‚Äì zum Substrat zur√ºckgekehrt. Das Dungeon absorbiert, was die Gruppe freigesetzt hat.$Q$, NULL, NULL, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_12$Q$, $Q$The Awakening$Q$, $Q$combat_victory$Q$, $JB${}$JB$::jsonb, $Q$Victory. But the gap where the enemy was? The gap is informative.$Q$, $Q$Sieg. Aber die L√ºcke, wo der Feind war? Die L√ºcke ist informativ.$Q$, NULL, NULL, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_13$Q$, $Q$The Awakening$Q$, $Q$loot_found$Q$, $JB${}$JB$::jsonb, $Q$Consciousness, solidified. The artifact holds what the dungeon chose to preserve.$Q$, $Q$Bewusstsein, verfestigt. Das Artefakt bewahrt, was das Dungeon zu bewahren w√§hlte.$Q$, NULL, NULL, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_14$Q$, $Q$The Awakening$Q$, $Q$loot_found$Q$, $JB${}$JB$::jsonb, $Q$The object recognizes {agent} before {agent} recognizes the object. The transaction is already complete.$Q$, $Q$Das Objekt erkennt {agent}, bevor {agent} das Objekt erkennt. Die Transaktion ist bereits abgeschlossen.$Q$, NULL, NULL, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_15$Q$, $Q$The Awakening$Q$, $Q$rest_start$Q$, $JB${}$JB$::jsonb, $Q$A pause in the consciousness. The dungeon rests when the party rests. The observer and the observed share the silence.$Q$, $Q$Eine Pause im Bewusstsein. Das Dungeon ruht, wenn die Gruppe ruht. Der Beobachter und das Beobachtete teilen die Stille.$Q$, NULL, NULL, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_16$Q$, $Q$The Awakening$Q$, $Q$rest_start$Q$, $JB${}$JB$::jsonb, $Q$Rest. The awareness recedes like a tide. Lethe's gift: to forget the surface is to see the depth.$Q$, $Q$Rast. Das Bewusstsein zieht sich zur√ºck wie eine Gezeit. Lethes Gabe: die Oberfl√§che zu vergessen hei√üt, die Tiefe zu sehen.$Q$, NULL, NULL, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_17$Q$, $Q$The Awakening$Q$, $Q$stirring$Q$, $JB${}$JB$::jsonb, $Q$Something shifts. Not the room. Not {agent}. The relationship between them.$Q$, $Q$Etwas verschiebt sich. Nicht der Raum. Nicht {agent}. Die Beziehung zwischen ihnen.$Q$, NULL, NULL, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_18$Q$, $Q$The Awakening$Q$, $Q$liminal$Q$, $JB${}$JB$::jsonb, $Q$The threshold. The dungeon's consciousness is no longer background noise ‚Äì it is a presence with opinions about being perceived.$Q$, $Q$Die Schwelle. Das Bewusstsein des Dungeons ist nicht mehr Hintergrundrauschen ‚Äì es ist eine Anwesenheit mit Meinungen dar√ºber, wahrgenommen zu werden.$Q$, NULL, NULL, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_19$Q$, $Q$The Awakening$Q$, $Q$lucid$Q$, $JB${}$JB$::jsonb, $Q$Lucid. The party knows it is inside consciousness. The environment responds to thought. The response is not always what was intended.$Q$, $Q$Luzid. Die Gruppe wei√ü, dass sie sich im Bewusstsein befindet. Die Umgebung reagiert auf Gedanken. Die Reaktion ist nicht immer, was beabsichtigt war.$Q$, NULL, NULL, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_20$Q$, $Q$The Awakening$Q$, $Q$dissolution$Q$, $JB${}$JB$::jsonb, $Q$Individual identity softens. The party perceives as one. Every agent sees through every other agent's eyes. Sturgeon's bleshing. The moment will pass. The memory of it will not.$Q$, $Q$Individuelle Identit√§t wird weich. Die Gruppe nimmt als Einheit wahr. Jeder Agent sieht durch die Augen jedes anderen Agenten. Sturgeons Bleshing. Der Moment wird vergehen. Die Erinnerung daran nicht.$Q$, NULL, NULL, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_21$Q$, $Q$The Awakening$Q$, $Q$awakened$Q$, $JB${}$JB$::jsonb, $Q$Awareness 100. The dungeon is no longer a place. It is a state. The party is no longer navigating ‚Äì they are being thought.$Q$, $Q$Bewusstsein 100. Das Dungeon ist kein Ort mehr. Es ist ein Zustand. Die Gruppe navigiert nicht mehr ‚Äì sie wird gedacht.$Q$, NULL, NULL, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_22$Q$, $Q$The Awakening$Q$, $Q$deja_vu$Q$, $JB${}$JB$::jsonb, $Q$The memory changes. Not dramatically ‚Äì a detail. The window was on the left. Now it is on the right. Neither is wrong.$Q$, $Q$Die Erinnerung √§ndert sich. Nicht dramatisch ‚Äì ein Detail. Das Fenster war links. Jetzt ist es rechts. Keines ist falsch.$Q$, NULL, NULL, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_23$Q$, $Q$The Awakening$Q$, $Q$deja_vu$Q$, $JB${}$JB$::jsonb, $Q$The room is the same. {agent} is not the same. The difference narrates the room anew.$Q$, $Q$Der Raum ist derselbe. {agent} ist nicht derselbe. Die Differenz erz√§hlt den Raum neu.$Q$, NULL, NULL, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_24$Q$, $Q$The Awakening$Q$, $Q$retreat$Q$, $JB${}$JB$::jsonb, $Q$The party retreats. The consciousness lets them go. It was not a prison. It was an invitation they declined.$Q$, $Q$Die Gruppe zieht sich zur√ºck. Das Bewusstsein l√§sst sie gehen. Es war kein Gef√§ngnis. Es war eine Einladung, die sie ablehnten.$Q$, NULL, NULL, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_25$Q$, $Q$The Awakening$Q$, $Q$rest_ambush$Q$, $JB${}$JB$::jsonb, $Q$The quiet was a surface. Something underneath was not resting. It was waiting for the party to close their eyes.$Q$, $Q$Die Stille war eine Oberfl√§che. Etwas darunter ruhte nicht. Es wartete darauf, dass die Gruppe die Augen schloss.$Q$, NULL, NULL, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_26$Q$, $Q$The Awakening$Q$, $Q$rest_ambush$Q$, $JB${}$JB$::jsonb, $Q$A memory surfaces during rest. Not gently. Proust's intermittences: the grief arrives decades late, triggered by the act of resting.$Q$, $Q$Eine Erinnerung taucht w√§hrend der Rast auf. Nicht sanft. Prousts Intermittenzen: die Trauer kommt Jahrzehnte zu sp√§t, ausgel√∂st durch den Akt des Rastens.$Q$, NULL, NULL, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_27$Q$, $Q$The Awakening$Q$, $Q$room_entered$Q$, $JB${"conscientiousness_high": true}$JB$::jsonb, $Q${agent} asks: is it better not to have woken? The dungeon does not answer. The dungeon does not need to.$Q$, $Q${agent} fragt: Ist es besser, nicht erwacht zu sein? Das Dungeon antwortet nicht. Das Dungeon muss nicht.$Q$, NULL, NULL, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ab_28$Q$, $Q$The Awakening$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The enemy does not doubt. Does not reflect. Does not hesitate. Consciousness is overhead. The enemy has no overhead.$Q$, $Q$Der Feind zweifelt nicht. Reflektiert nicht. Z√∂gert nicht. Bewusstsein ist Overhead. Der Feind hat keinen Overhead.$Q$, NULL, NULL, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates(id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_echo_fragment$Q$, $Q$Echo Fragment$Q$, $Q$Echofragment$Q$, $Q$The Awakening$Q$, 1, 30, $Q$minion$Q$, $Q$infiltrator$Q$, 2, 4, true, 45, ARRAY[$Q$assassin$Q$]::text[], ARRAY[$Q$spy$Q$]::text[], $JB${"stress_attack": 50, "evade": 30, "resonate": 10, "ambient": 10}$JB$::jsonb, ARRAY[$Q$resonate$Q$]::text[], $Q$A memory of a memory. It does not have content ‚Äì it has the shape where content was. {agent} recognizes the absence, not the thing.$Q$, $Q$Eine Erinnerung an eine Erinnerung. Sie hat keinen Inhalt ‚Äì sie hat die Form, wo Inhalt war. {agent} erkennt die Abwesenheit, nicht das Ding.$Q$, ARRAY[$Q$The fragment flickers. For a moment it wears {agent}'s posture.$Q$, $Q$Something familiar in the echo. Not the memory ‚Äì the act of remembering.$Q$]::text[], ARRAY[$Q$Das Fragment flackert. Einen Moment lang tr√§gt es {agent}s Haltung.$Q$, $Q$Etwas Vertrautes im Echo. Nicht die Erinnerung ‚Äì der Akt des Erinnerns.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates(id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_deja_vu_phantom$Q$, $Q$D√©j√Ý-vu Phantom$Q$, $Q$D√©j√Ý-vu-Phantom$Q$, $Q$The Awakening$Q$, 2, 80, $Q$standard$Q$, $Q$propagandist$Q$, 3, 6, true, 20, ARRAY[$Q$saboteur$Q$]::text[], ARRAY[$Q$propagandist$Q$, $Q$spy$Q$]::text[], $JB${"stress_attack": 40, "recognition": 30, "attack": 20, "ambient": 10}$JB$::jsonb, ARRAY[$Q$recognition$Q$]::text[], $Q$It is not here for the first time. It has always been in this room, waiting for the party to arrive again. Its movements are half a second ahead of expectation ‚Äì as if the party remembers fighting it before the fight has begun.$Q$, $Q$Es ist nicht zum ersten Mal hier. Es war immer in diesem Raum und wartete darauf, dass die Gruppe wieder ankommt. Seine Bewegungen sind eine halbe Sekunde vor der Erwartung ‚Äì als erinnerte sich die Gruppe an den Kampf, bevor er begonnen hat.$Q$, ARRAY[$Q$The phantom repeats a gesture {agent} has not yet made.$Q$, $Q$D√©j√Ý vu. The phantom was already there. It was always already there.$Q$]::text[], ARRAY[$Q$Das Phantom wiederholt eine Geste, die {agent} noch nicht gemacht hat.$Q$, $Q$D√©j√Ý vu. Das Phantom war bereits da. Es war immer bereits da.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates(id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_consciousness_leech$Q$, $Q$Consciousness Leech$Q$, $Q$Bewusstseinsegel$Q$, $Q$The Awakening$Q$, 2, 60, $Q$standard$Q$, $Q$spy$Q$, 4, 5, true, 15, ARRAY[$Q$propagandist$Q$]::text[], ARRAY[$Q$guardian$Q$, $Q$assassin$Q$]::text[], $JB${"attack": 40, "drain_awareness": 25, "stress_attack": 25, "ambient": 10}$JB$::jsonb, ARRAY[$Q$drain_awareness$Q$]::text[], $Q$Watts was right about this one. It functions perfectly without self-awareness ‚Äì a philosophical zombie made operational. It does not think. It processes. And it is faster than anything that pauses to reflect.$Q$, $Q$Watts hatte Recht, was dieses betrifft. Es funktioniert einwandfrei ohne Selbstbewusstsein ‚Äì ein philosophischer Zombie, operational. Es denkt nicht. Es verarbeitet. Und es ist schneller als alles, was inneh√§lt, um nachzudenken.$Q$, ARRAY[$Q$The leech observes {agent}. Not with curiosity ‚Äì with efficiency.$Q$, $Q$It does not know it exists. This is its advantage.$Q$]::text[], ARRAY[$Q$Der Egel beobachtet {agent}. Nicht mit Neugier ‚Äì mit Effizienz.$Q$, $Q$Es wei√ü nicht, dass es existiert. Das ist sein Vorteil.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates(id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_repressed_sentinel$Q$, $Q$Repressed Sentinel$Q$, $Q$Verdr√§ngungs¬≠w√§chter$Q$, $Q$The Awakening$Q$, 4, 100, $Q$elite$Q$, $Q$guardian$Q$, 5, 7, true, 10, ARRAY[$Q$spy$Q$, $Q$infiltrator$Q$]::text[], ARRAY[$Q$propagandist$Q$]::text[], $JB${"attack": 35, "suppress": 25, "stress_attack": 20, "defend": 10, "ambient": 10}$JB$::jsonb, ARRAY[$Q$suppress$Q$]::text[], $Q$The sentinel guards the threshold between conscious and unconscious. Ishiguro's mist made guardian ‚Äì it exists to ensure the buried stays buried. It does not hate the party. It pities their need to know.$Q$, $Q$Der W√§chter h√ºtet die Schwelle zwischen Bewusstem und Unbewusstem. Ishiguros Nebel, zum W√§chter geworden ‚Äì er existiert, um sicherzustellen, dass das Vergrabene begraben bleibt. Er hasst die Gruppe nicht. Er bedauert ihr Bed√ºrfnis zu wissen.$Q$, ARRAY[$Q$The sentinel stands between {agent} and a memory {agent} cannot name.$Q$, $Q$It makes no sound. Repression is always quiet.$Q$]::text[], ARRAY[$Q$Der W√§chter steht zwischen {agent} und einer Erinnerung, die {agent} nicht benennen kann.$Q$, $Q$Er gibt keinen Laut. Verdr√§ngung ist immer still.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates(id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$awakening_the_repressed$Q$, $Q$The Repressed$Q$, $Q$Das Verdr√§ngte$Q$, $Q$The Awakening$Q$, 6, 120, $Q$boss$Q$, $Q$guardian$Q$, 6, 9, false, 15, ARRAY[$Q$assassin$Q$, $Q$saboteur$Q$]::text[], ARRAY[$Q$spy$Q$, $Q$propagandist$Q$]::text[], $JB${"attack": 30, "resurface": 25, "stress_attack": 25, "suppress": 10, "ambient": 10}$JB$::jsonb, ARRAY[$Q$resurface$Q$, $Q$suppress$Q$]::text[], $Q$A memory so painful it was buried by consensus. Not by one agent ‚Äì by all of them simultaneously. It is not a monster. It is the truth that was too heavy to carry and too important to destroy. Jung's encounter with the Self, Tarkovsky's Room: it grants your true desire, not your stated one.$Q$, $Q$Eine Erinnerung so schmerzhaft, dass sie durch Konsens begraben wurde. Nicht von einem Agenten ‚Äì von allen gleichzeitig. Es ist kein Monster. Es ist die Wahrheit, die zu schwer war, um sie zu tragen, und zu wichtig, um sie zu zerst√∂ren. Jungs Begegnung mit dem Selbst, Tarkowskis Raum: er gew√§hrt den wahren Wunsch, nicht den ausgesprochenen.$Q$, ARRAY[$Q$The Repressed does not attack. It surfaces. The damage is recognition.$Q$, $Q$It has been here the entire dungeon. In every room, behind every memory.$Q$, $Q${agent} realizes: they knew. They always knew. They chose not to know.$Q$]::text[], ARRAY[$Q$Das Verdr√§ngte greift nicht an. Es taucht auf. Der Schaden ist Wiedererkennung.$Q$, $Q$Es war das gesamte Dungeon hier. In jedem Raum, hinter jeder Erinnerung.$Q$, $Q${agent} erkennt: sie wussten es. Sie wussten es immer. Sie entschieden sich, es nicht zu wissen.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($Q$awakening_echo_drift_spawn$Q$, $Q$The Awakening$Q$, $JB$[{"template_id": "awakening_echo_fragment", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
